const add = function(a, b) {
	let sum = a + b;
  return sum;
};

const subtract = function(c, d) {
  return c - d;	
};

const sum = function(arr) {
  let total = 0;
  for (number of arr) {
    total += number;
  }	
  return total;
};



const multiply = function(arr) {
  let total = 1;
  for (number of arr) {
    total *= number;
  }	
  return total;
};




const power = function(base, exponent) {
    return base ** exponent;		
};




const factorial = function(num) {
	let total = 1;
  for (let i = 1; i <= num; i++) {
    total *= i;
  }	
  return total;
};




